VALUES
  ('police-b20a8cf8-moex-00574', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關刑案現場逮捕犯罪嫌疑人，下列敘述那些正確？①得附帶搜索其身體、隨身攜帶之物品', '["得使用警械防止其脫逃", "逮捕之犯罪嫌疑人應與被害人、目擊證人或其他參與犯罪者隔離", "於刑案現場逮捕犯罪嫌疑人時，應立即帶離  ⑤於刑案現場以外之處所逮捕時，應帶回現場", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00575', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '實施跟蹤期間，被跟蹤對象在行進間突然停止、轉身反顧，觀察是否有人跟蹤時，依警察偵查犯', '["儘速撤離", "若無其事並保持自然行走狀態", "立即停 止跟蹤，重新部署", "佯裝向人問路、交談  ⑤視情況通知其他人員繼續跟蹤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00576', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關通知犯罪嫌疑人到場詢問，下列敘述那些正確？①司法警察為蒐集證據，得使用通知書，通', '["通知書應由警察局長或相當職務以上長官簽章", "通知書指派 員警送達者，應於非例假日之日間行之", "對於無急迫性或時效性之案件，通知書以寄存送達方 式為原則  ⑤案件未經調查且非有必要，不得任意通知犯罪嫌疑人到場", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00577', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關槍彈證物之處理原則，下列敘述那些正確？①子彈、彈頭（殼）應直接以金屬器具夾取', '["彈頭（殼）宜以證物袋合併統一包裝，以免散失", "現場槍枝採取前宜先記錄其原始狀態，確 認安全無虞後，放入證物袋或證物盒中保存", "槍枝有同時採取二種以上跡證之需要者，應注意 採證之順序  ⑤警察機關查獲涉槍案件，宜由查獲單位或委由查獲地警察機關進行槍枝初步檢視", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00578', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關詢問犯罪嫌疑人，下列敘述那些正確？①詢問開始前，詢問人員應先行了解全盤案情  ②詢問', '["詢問時之錄音及錄影，應自詢問案件事實時起錄， 至詢問完畢時停止", "詢問時應結合現場勘察、物證蒐採等情資，作為案情研判依據  ⑤不得於 夜間詢問，但經受詢問人明示同意者，不在此限", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00579', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '依法拘提之犯罪嫌疑人，經令其出示相關身分證明文件，而仍無法出示相關證明文件，必要時得', '["比對偵查卷內之簽名是否相符", "比對偵查卷內之照片是否相 符", "採取指紋，循個人身分識別系統查驗", "通知被害人到場指認  ⑤通知犯罪嫌疑人之家屬 前來指認"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00580', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關執行拘提，下列敘述何者正確？①執行前應深入了解案情  ②應講求團隊合作默契  ③執行', '["對抗拒拘提者，必要時得使用警械  ⑤應顧及本身安全", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00581', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關偵查中選任辯護人，下列敘述何者正確？', '["辯護人不以律師為限", "每一犯罪嫌疑人選任之辯護人以一人為限", "犯罪嫌疑人選任辯護人應提出委任書狀，並以司法狀紙為限", "司法警察官收受委任書狀後，應查對律師登錄名簿，合於規定者，應將詢問之日、時及處所通 知辯護人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00582', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關搜索、扣押之執行，下列敘述那些正確？①在有人看守之處所內行搜索或扣押者，應命看守', '["搜索應保守秘密", "執行搜索時，得禁止在場人員離去，對於違反 禁止命令者，得交由適當之人看守", "日間執行搜索者，應於日沒前中止搜索，必要時應將該處 閉鎖，並派人看守  ⑤旅店、飲食店或其他於夜間公眾可以出入之處所，雖非公開時間，仍得於 夜間入內搜索或扣押", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00583', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關調取通信紀錄，下列敘述何者正確？', '["司法警察官偵辦誹謗罪之案件，得報請檢察官許可後，向該管法院聲請核發調取票", "偵辦公然侮辱罪之案件，不得調取通信紀錄", "司法警察官偵辦竊盜罪之案件，得向檢察官聲請同意後，調取通信紀錄，不必向法院聲請調取票", "偵辦侵占罪之案件，不得調取通信紀錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "e7a1abb09da3", "answer_pdf_sha1": "fa18dd0746b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
